script.body:
param([string]$RepoPath = '.')
Push-Location $RepoPath
try {
    $status = git status --porcelain
    if (-not $status) {
        Write-Output 'Working tree clean - no changes'
    } else {
        Write-Output '=== Git Status ==='
        $staged = $status | Where-Object { $_ -match '^[MADRCU]' }
        $unstaged = $status | Where-Object { $_ -match '^.[MADRCU]' }
        $untracked = $status | Where-Object { $_ -match '^\?\?' }
        if ($staged) {
            Write-Output "`nStaged for commit:"
            $staged | ForEach-Object { Write-Output "  $_" }
        }
        if ($unstaged) {
            Write-Output "`nNot staged:"
            $unstaged | ForEach-Object { Write-Output "  $_" }
        }
        if ($untracked) {
            Write-Output "`nUntracked files:"
            $untracked | ForEach-Object { Write-Output "  $_" }
        }
    }
} finally {
    Pop-Location
}
